/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 5362; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_sanitizers_static_analysis_fuzzing_2(int spatial, int temporal, int uninitialized, int race) {
  int tools = 0;
  if (spatial || temporal) tools |= 1;
  if (uninitialized) tools |= 2;
  if (race) tools |= 4;
  return tools;
}

int main(void) {
  int first = worked_cmem_sanitizers_static_analysis_fuzzing_2(1, 0, 0, 0);
  int changed = worked_cmem_sanitizers_static_analysis_fuzzing_2(0, 0, 1, 1);
  int invariant = first == 1 && changed == 6 && 2 > 0;
  printf("tool-matrix first=%d changed=%d invariant=%d\n", first, changed, invariant);
  return invariant ? 0 : 1;
}

